const raw = $input.first().json;
const input = raw.body || raw;
if (!input.brand_name) throw new Error('brand_name is required');
if (!input.product_category) throw new Error('product_category is required');
if (!input.ad_screenshots || input.ad_screenshots.length === 0) throw new Error('ad_screenshots array is required and must not be empty');
if (!input.review_texts || input.review_texts.length === 0) throw new Error('review_texts array is required and must not be empty');
const runId = input.run_id || (Date.now().toString(36) + Math.random().toString(36).slice(2));
return [{ json: { ...input, run_id: runId, started_at: input.started_at || new Date().toISOString() } }];

return $input.all().map(function(item, i) {
  var response = item.json;
  if (response.error) throw new Error('Claude API error on ad ' + i + ': ' + JSON.stringify(response.error));
  if (!response.content || !response.content[0]) throw new Error('Empty Claude response on ad ' + i);
  var rawText = response.content[0].text;
  var parsed;
  try {
    var cleaned = rawText.replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();
    parsed = JSON.parse(cleaned);
  } catch(e) {
    throw new Error('Failed to parse Vision Analyst JSON for ad ' + i + ': ' + e.message + '\nRaw: ' + rawText.slice(0, 300));
  }
  // Normalise top-level keys to lowercase snake_case (Claude sometimes returns UPPER_CASE section headers)
  var normalised = {};
  Object.keys(parsed).forEach(function(k) { normalised[k.toLowerCase()] = parsed[k]; });
  var usage = response.usage || {};
  return {
    json: {
      ad_index: i,
      competitor_name: item.json.competitor_name || ('Competitor ' + (i + 1)),
      model_used: response.model || 'claude-sonnet-4-6',
      input_tokens: usage.input_tokens || 0,
      output_tokens: usage.output_tokens || 0,
      cache_creation_input_tokens: usage.cache_creation_input_tokens || 0,
      cache_read_input_tokens: usage.cache_read_input_tokens || 0,
      analysis: normalised
    }
  };
});

var analyses = $input.all().filter(function(a) { return !a.json.error && a.json.analysis; });
var layoutCounts = {}, formulaCounts = {}, offerTypeCounts = {}, toneCounts = {}, spendTierCounts = {}, trustElementCounts = {};
var faceCount = 0, comparisonCount = 0;
var adSummaries = [];
for (var i = 0; i < analyses.length; i++) {
  var a = analyses[i].json.analysis;
  var vs = a.visual_structure, ca = a.copy_analysis, oah = a.offer_and_hook, bs = a.brand_signals, cq = a.creative_quality;
  layoutCounts[vs.layout_type] = (layoutCounts[vs.layout_type] || 0) + 1;
  if (ca.headline_formula) formulaCounts[ca.headline_formula] = (formulaCounts[ca.headline_formula] || 0) + 1;
  if (oah.offer_type) offerTypeCounts[oah.offer_type] = (offerTypeCounts[oah.offer_type] || 0) + 1;
  if (ca.tone) toneCounts[ca.tone] = (toneCounts[ca.tone] || 0) + 1;
  if (cq.estimated_ad_spend_tier) spendTierCounts[cq.estimated_ad_spend_tier] = (spendTierCounts[cq.estimated_ad_spend_tier] || 0) + 1;
  if (vs.has_human_face) faceCount++;
  if (bs.competitor_comparison) comparisonCount++;
  (bs.trust_elements || []).forEach(function(te) { trustElementCounts[te] = (trustElementCounts[te] || 0) + 1; });
  adSummaries.push({ competitor: analyses[i].json.competitor_name || 'Unknown', layout: vs.layout_type, headline: ca.headline || '(none)', offer: oah.offer_type, hook_formula: ca.headline_formula, spend_tier: cq.estimated_ad_spend_tier, primary_hook: oah.primary_hook, tone: ca.tone });
}
function top(obj, n) { return Object.entries(obj).sort(function(a,b){return b[1]-a[1];}).slice(0,n||3).map(function(e){return e[0]+' ('+e[1]+'x)';}).join(', '); }
var total = analyses.length;
var summary = 'COMPETITOR AD ANALYSIS - ' + total + ' ads

VISUAL PATTERNS:
- Dominant layouts: ' + top(layoutCounts) + '
- Ads with human faces: ' + faceCount + '/' + total + '
- Competitor comparisons: ' + comparisonCount + '/' + total + '

COPY PATTERNS:
- Headline formulas: ' + top(formulaCounts) + '
- Tones: ' + top(toneCounts) + '
- Offer types: ' + top(offerTypeCounts) + '
- Trust elements: ' + top(trustElementCounts) + '

SPEND TIERS:
' + Object.entries(spendTierCounts).map(function(e){return '- '+e[0]+': '+e[1]+' ads';}).join('
') + '

PER-AD HOOKS:
' + adSummaries.map(function(ad, i) { return '[Ad '+(i+1)+'] '+ad.competitor+' | '+ad.hook_formula+' | '+ad.tone+'
  Headline: "'+ad.headline+'"
  Hook: '+ad.primary_hook; }).join('

');
return [{ json: { vision_analysis_summary: summary, ad_summaries: adSummaries, total_ads_analysed: total, pattern_counts: { layouts: layoutCounts, headline_formulas: formulaCounts, offer_types: offerTypeCounts, tones: toneCounts, spend_tiers: spendTierCounts } } }];

return $input.all().map(function(item, i) {
  var response = item.json;
  if (response.error) throw new Error('Claude API error on review batch ' + i + ': ' + JSON.stringify(response.error));
  if (!response.content || !response.content[0]) throw new Error('Empty Claude response on review batch ' + i);
  var rawText = response.content[0].text;
  var parsed;
  try {
    var cleaned = rawText.replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();
    parsed = JSON.parse(cleaned);
  } catch(e) {
    throw new Error('Failed to parse Review Miner JSON for batch ' + i + ': ' + e.message);
  }
  var usage = response.usage || {};
  return {
    json: {
      batch_index: i,
      model_used: 'claude-haiku-4-5-20251001',
      input_tokens: usage.input_tokens || 0,
      output_tokens: usage.output_tokens || 0,
      cache_creation_input_tokens: usage.cache_creation_input_tokens || 0,
      cache_read_input_tokens: usage.cache_read_input_tokens || 0,
      result: parsed
    }
  };
});

var batches = $input.all();
var allReviews = [], painCounts = {}, desireCounts = {}, allHooks = [];
var totalSentiment = 0, totalReviews = 0, bestInsight = '';
for (var b = 0; b < batches.length; b++) {
  var result = batches[b].json.result;
  if (!result || batches[b].json.error) continue;
  var reviews = result.reviews || [];
  for (var r = 0; r < reviews.length; r++) {
    var rev = reviews[r];
    allReviews.push(rev);
    totalSentiment += rev.sentiment.score;
    totalReviews++;
    var pain = rev.pain_point.category;
    if (pain !== 'no_pain_point') painCounts[pain] = (painCounts[pain] || 0) + 1;
    var desire = rev.desire.category;
    if (desire !== 'no_desire_expressed') desireCounts[desire] = (desireCounts[desire] || 0) + 1;
    if (rev.hook_potential.usable_as_hook && rev.hook_potential.hook_candidate) allHooks.push(rev.hook_potential.hook_candidate);
  }
  if (result.aggregate && result.aggregate.brand_summary_insight) bestInsight = result.aggregate.brand_summary_insight;
}
function sortByCount(obj) {
  return Object.entries(obj).sort(function(a,b){return b[1]-a[1];}).map(function(e) {
    var cat = e[0], count = e[1];
    var verbatim = null;
    for (var i = 0; i < allReviews.length; i++) {
      if (allReviews[i].pain_point.category === cat && allReviews[i].pain_point.pain_verbatim) { verbatim = allReviews[i].pain_point.pain_verbatim; break; }
      if (allReviews[i].desire.category === cat && allReviews[i].desire.desire_verbatim) { verbatim = allReviews[i].desire.desire_verbatim; break; }
    }
    return { category: cat, count: count, percentage: totalReviews > 0 ? Math.round(count/totalReviews*1000)/10 : 0, best_verbatim: verbatim };
  });
}
var uniqueHooks = allHooks.filter(function(h, i, arr) { return arr.indexOf(h) === i; }).slice(0, 10);
return [{ json: { total_reviews_processed: totalReviews, overall_average_sentiment: totalReviews > 0 ? Math.round(totalSentiment/totalReviews*100)/100 : 0, top_pain_points: sortByCount(painCounts).slice(0, 5), top_desires: sortByCount(desireCounts).slice(0, 5), top_hook_candidates: uniqueHooks, brand_summary_insight: bestInsight } }];

var response = $input.first().json;
if (response.error) throw new Error('Hook Strategist API error: ' + JSON.stringify(response.error));
if (!response.content || !response.content[0]) throw new Error('Empty response from Hook Strategist');
var rawText = response.content[0].text;
var parsed;
try {
  var cleaned = rawText.replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Failed to parse Hook Strategist JSON: ' + e.message + '\nRaw: ' + rawText.slice(0, 300));
}
var usage = response.usage || {};
return [{ json: { ...parsed, input_tokens: usage.input_tokens || 0, output_tokens: usage.output_tokens || 0, model_used: response.model || 'claude-sonnet-4-6' } }];

var response = $input.first().json;
if (response.error) throw new Error('Report Writer API error: ' + JSON.stringify(response.error));
if (!response.content || !response.content[0]) throw new Error('Empty response from Report Writer');
var usage = response.usage || {};
return [{ json: { brand_report: response.content[0].text, input_tokens: usage.input_tokens || 0, output_tokens: usage.output_tokens || 0, model_used: response.model || 'claude-sonnet-4-6' } }];

var PRICE = { sonnet: { input: 3.00, output: 15.00, cacheWrite: 3.75, cacheRead: 0.30 }, haiku: { input: 0.80, output: 4.00, cacheWrite: 1.00, cacheRead: 0.08 } };
function cost(inp, out, cw, cr, model) { var p = PRICE[model]; var reg = Math.max(0, inp - (cw||0) - (cr||0)); return reg*p.input/1e6 + out*p.output/1e6 + (cw||0)*p.cacheWrite/1e6 + (cr||0)*p.cacheRead/1e6; }
function sumTok(items) { return items.reduce(function(acc, item) { return { input: acc.input+(item.json.input_tokens||0), output: acc.output+(item.json.output_tokens||0), cacheWrite: acc.cacheWrite+(item.json.cache_creation_input_tokens||0), cacheRead: acc.cacheRead+(item.json.cache_read_input_tokens||0) }; }, {input:0,output:0,cacheWrite:0,cacheRead:0}); }
var inputNode = $('Input Validator').first().json;
var visionMerger = $('Vision Results Merger').first().json;
var reviewAgg = $('Review Aggregator').first().json;
var hooksNode = $('Parse Hook Response').first().json;
var reportNode = $('Parse Report Response').first().json;
var visionItems = $('Parse Vision Response').all();
var reviewItems = $('Parse Review Response').all();
var vt = sumTok(visionItems), rt = sumTok(reviewItems);
var totalCost = cost(vt.input,vt.output,vt.cacheWrite,vt.cacheRead,'sonnet') + cost(rt.input,rt.output,rt.cacheWrite,rt.cacheRead,'haiku') + cost(hooksNode.input_tokens||0,hooksNode.output_tokens||0,0,0,'sonnet') + cost(reportNode.input_tokens||0,reportNode.output_tokens||0,0,0,'sonnet');
var completedAt = new Date().toISOString();
var durationSeconds = Math.round((new Date(completedAt)-new Date(inputNode.started_at))/1000);
var sortedHooks = (hooksNode.hooks||[]).slice().sort(function(a,b){return b.confidence_score-a.confidence_score;});
return [{ json: { run_id: inputNode.run_id, brand_name: inputNode.brand_name, started_at: inputNode.started_at, completed_at: completedAt, duration_seconds: durationSeconds, hooks: sortedHooks, brand_report: reportNode.brand_report || '', strategy_brief: hooksNode.strategy_brief || null, run_stats: { ads_analysed: visionMerger.total_ads_analysed||visionItems.length, reviews_processed: reviewAgg.total_reviews_processed||0, hooks_generated: sortedHooks.length, total_input_tokens: vt.input+rt.input+(hooksNode.input_tokens||0)+(reportNode.input_tokens||0), total_output_tokens: vt.output+rt.output+(hooksNode.output_tokens||0)+(reportNode.output_tokens||0), estimated_cost_usd: Math.round(totalCost*10000)/10000, sonnet_calls: visionItems.length+2, haiku_calls: reviewItems.length } } }];
